#!/usr/bin/env python

# loop over windows and aggregate into groups which are nested
# if any of the nested groups are smaller than some threshold, then
# merge them into the higher level group

from .peeking_sort import *
from .reader_utils import BED12Record, parse_bed12_line
from typing import Generator, List, Tuple
from functools import partial
from scipy import sparse
from numpy import array, ones_like
from itertools import chain


def coarsen_regions(
        regions : Generator[BED12Record, None, None],
        windowsize_threshold : int = 1000,    
    ):

    idx = lambda i : lambda x : x[i]
    compose = lambda g, f : lambda x : f(g(x))

    def collapse_group(
            group : List[Tuple[int, Tuple[str, int, int, int]]],
            windowsize_threshold : int = 1000,
    ):
        '''
        Given a list of overlapping or nested regions, 
        remove any regions that are smaller than the windowsize_threshold
        by setting their window index to 0. This index is shared by the
        largest region in the group.

        The return format is a bituple where the elements are:
        (index of the region in the original list, new window index - counting from 0 within the group)
        '''
        
        # get the largest window by length
        get_length = compose(idx(1), idx(3))
        (i, _)= max( group, key = get_length )

        for j, region in group:
            if idx(3)(region) < windowsize_threshold:
                yield (j, i)
            else:
                yield (j, j)


    data = map(lambda x : (x.chromosome, x.start, x.end, len(x)), regions)

    data = enumerate(map(expand_args(RegionOverlapComparitor), data) )

    data = buffered_aggregator(
        data,
        has_lapsed = lambda current, buffer : all(idx(1)(current) > idx(1)(b) for b in buffer),
        key = lambda _ : True,
        order_key=idx(1),
        buffer_summary=lambda x : x,
    )

    data = map(lambda x : [(i,_x.unwrap()) for i, _x in x], data)

    data : Generator[Tuple[int, int], None, None] = \
        map(compose(partial(collapse_group, windowsize_threshold=windowsize_threshold), list), data)
    
    projection_coors = chain.from_iterable(data)

    i,j = list(zip(*projection_coors))
    i=array(i); j=array(j)
    projection_matrix = sparse.coo_matrix((ones_like(i), (i, j))).tocsc()

    return (
        projection_matrix, i, j,
    )

        
